import { Select } from '@/components/atoms/Select/Select';
import { countries } from './countries';
import type { SelectProps as BaseSelectProps } from '@/components/atoms/Select';
import { WithDataId } from '@/types/withDataId';
import { FlagIcon } from '@/components/atoms/FlagIcon';
import type { ReactNode } from 'react';

// Transform countries object into items format expected by Select
const countryItems = Object.entries(countries).map(([id, label]) => ({
  id,
  label,
}));

type CountryItem = {
  id: string;
  label: string;
  icon?: ReactNode;
  /**
   * Extra strings to match against when `searchable` is enabled (e.g.
   * localized country names). Case-insensitive substring match.
   */
  searchAliases?: string[];
};

export interface CountrySelectProps
  extends Omit<BaseSelectProps, 'children' | 'items'>, WithDataId {
  /**
   * Optional custom items to override the default countries list.
   * If not provided, uses the full list of countries.
   */
  items?: CountryItem[];
  /**
   * Visual variant. `flag` renders a circular country flag in the trigger
   * and each item; `default` shows label only.
   */
  variant?: 'default' | 'flag';
}

/**
 * A Select component pre-configured with all world countries.
 *
 * This component wraps the base Select component and provides
 * a comprehensive list of countries as options.
 */
export function CountrySelect({
  items = countryItems,
  label = 'Country',
  placeholder = 'Select country',
  variant = 'default',
  texts,
  ...props
}: CountrySelectProps) {
  const resolvedItems =
    variant === 'flag'
      ? items.map((item) =>
          item.icon ? item : { ...item, icon: <FlagIcon flag={item.id} /> },
        )
      : items;

  const mergedTexts = {
    searchNotFound: 'No countries found',
    ...texts,
  };

  return (
    <Select
      label={label}
      placeholder={placeholder}
      items={resolvedItems}
      texts={mergedTexts}
      {...props}
    />
  );
}
