import {
  Select as BaseSelect,
  type SelectProps as BaseSelectProps,
  type SelectItemType,
} from './BaseSelect';
import { SelectItem } from './BaseSelectItem';
import { Key } from 'react-aria-components';
import { WithDataId } from '@/types/withDataId';
import { FieldWrapper } from '@/components/molecules/FieldWrapper';
import { FieldWrapperProps } from '@/components/molecules/FieldWrapper/FieldWrapper';

export interface SelectProps
  extends
    Omit<
      BaseSelectProps,
      'isRequired' | 'children' | 'ref' | 'hint' | 'label' | 'isInvalid'
    >,
    Omit<FieldWrapperProps, 'children'>,
    WithDataId {
  children?: React.ReactNode | ((item: SelectItemType) => React.ReactNode);
  required?: BaseSelectProps['isRequired'];
  // necessary to avoid tsc problems inferring the value
  onChange?: (key: Key | null) => void;
}

function Select({
  required,
  items,
  preparedOptions,
  'data-id': dataId,
  label,
  hint,
  isInvalid,
  isRequired,
  tooltip,
  description,
  id = '',
  fieldSize = 'md',
  labelPosition = 'left',
  ...props
}: SelectProps) {
  return (
    <FieldWrapper
      id={id}
      isRequired={required || isRequired}
      tooltip={tooltip}
      label={label}
      isInvalid={isInvalid}
      labelPosition={labelPosition}
      hint={hint}
      fieldSize={fieldSize}
      description={description}
    >
      <BaseSelect
        items={items}
        preparedOptions={preparedOptions}
        data-id={dataId}
        isInvalid={isInvalid}
        {...props}
      >
        {props.children ||
          ((item) => (
            <SelectItem
              key={item.id}
              data-id={`${dataId}-${item.id}`}
              {...item}
            />
          ))}
      </BaseSelect>
    </FieldWrapper>
  );
}

Select.Item = SelectItem;

export { Select };
